    // Top-left corner
    if (tx == 0 && ty == 0) {
        unsigned char val = 0;
        const int gx = x - 1;
        const int gy = y - 1;
        if (gx >= 0 && gy >= 0) {
            const int g_idx = gy * width + gx;
            val = input[g_idx];
        }
        tile[0 * tile_width + 0] = val;
    }

    // Top-right corner
    if (tx == BLOCK_X - 1 && ty == 0) {
        unsigned char val = 0;
        const int gx = x + 1;
        const int gy = y - 1;
        if (gx < width && gy >= 0) {
            const int g_idx = gy * width + gx;
            val = input[g_idx];
        }
        tile[0 * tile_width + (BLOCK_X + 1)] = val;
    }

    // Bottom-left corner
    if (tx == 0 && ty == BLOCK_Y - 1) {
        unsigned char val = 0;
        const int gx = x - 1;
        const int gy = y + 1;
        if (gx >= 0 && gy < height) {
            const int g_idx = gy * width + gx;
            val = input[g_idx];
        }
        tile[(BLOCK_Y + 1) * tile_width + 0] = val;
    }

    // Bottom-right corner
    if (tx == BLOCK_X - 1 && ty == BLOCK_Y - 1) {
        unsigned char val = 0;
        const int gx = x + 1;
        const int gy = y + 1;
        if (gx < width && gy < height) {
            const int g_idx = gy * width + gx;
            val = input[g_idx];
        }
        tile[(BLOCK_Y + 1) * tile_width + (BLOCK_X + 1)] = val;
