#include <cuda_runtime.h>
#include <cstdint>

/*
 * CUDA implementation of Conway's Game of Life on a square grid.
 *
 * Input/output format:
 * - The logical grid is grid_dimensions x grid_dimensions cells.
 * - Each cell is 0 (dead) or 1 (alive).
 * - On the device, the external API exposes the grid in bit-packed form:
 *     * A std::uint64_t encodes an 8x8 tile of cells.
 *     * Tiles are laid out in row-major order:
 *         tile_index = tile_y * (grid_dimensions / 8) + tile_x
 *       where (tile_x, tile_y) is the tile's coordinate.
 *     * Within a tile, bits are laid out in row-major order:
 *         bit_index = local_y * 8 + local_x
 *       where (local_x, local_y) are coordinates in [0, 7].
 *
 * Implementation strategy:
 * - For simplicity and performance on modern GPUs, the actual
 *   computation of the next generation is done on a dense
 *   1-byte-per-cell representation:
 *     * 0 byte => dead cell
 *     * 1 byte => alive cell
 * - We perform three kernels:
 *     1) unpack_tiles_kernel: bit-packed tiles -> dense byte grid
 *     2) game_of_life_step_kernel: one Game of Life step on the byte grid
 *     3) pack_tiles_kernel: dense byte grid -> bit-packed tiles
 *
 * Notes:
 * - Shared and texture memory are not used, since global memory access
 *   with a well-shaped grid/block configuration is sufficient on H100/A100.
 * - Any data transformation (unpack/pack) overhead is assumed acceptable
 *   per the problem statement.
 * - The caller is responsible for host-device synchronization;
 *   this code does not call cudaDeviceSynchronize.
 */


/*
 * Kernel 1: Unpack bit-packed 8x8 tiles into a dense 1-byte-per-cell grid.
 */
__global__ void unpack_tiles_kernel(const std::uint64_t* __restrict__ input,
                                    std::uint8_t* __restrict__ dense_grid,
                                    int grid_dim)
{
    const int tiles_per_row = grid_dim / 8;
    const int num_tiles     = tiles_per_row * tiles_per_row;

    int tile_index = blockIdx.x * blockDim.x + threadIdx.x;
    if (tile_index >= num_tiles) return;

    // Determine tile coordinates in the grid of tiles.
    int tile_y = tile_index / tiles_per_row;
    int tile_x = tile_index % tiles_per_row;

    // Base coordinates of this tile in the cell grid.
    const int base_x = tile_x * 8;
    const int base_y = tile_y * 8;

    std::uint64_t word = input[tile_index];

    // Unpack 8x8 cells from the 64-bit word into dense_grid.
    // bit_index = local_y * 8 + local_x.
#pragma unroll
    for (int local_y = 0; local_y < 8; ++local_y) {
        // Extract the 8 bits for this row as a byte.
        std::uint8_t row_bits = static_cast<std::uint8_t>(word >> (local_y * 8));
        const int global_y    = base_y + local_y;
        const int row_offset  = global_y * grid_dim + base_x;

#pragma unroll
        for (int local_x = 0; local_x < 8; ++local_x) {
            std::uint8_t bit = (row_bits >> local_x) & 0x1u;
            dense_grid[row_offset + local_x] = bit;
        }
    }
}


/*
 * Kernel 2: Compute one Game of Life step on a dense 1-byte-per-cell grid.
 *
 * - grid_in:  current generation, values 0 or 1
 * - grid_out: next generation,    values 0 or 1
 * - grid_dim: width/height of the square grid
 *
 * Every thread updates exactly one cell.
 *
 * Boundary handling:
 * - Cells outside the grid are logically dead, i.e., neighbor accesses
 *   beyond the border contribute 0.
 * - For performance, interior cells (1 <= x < dim-1, 1 <= y < dim-1)
 *   use a fast path with no bounds checks.
 *   Boundary cells use a separate path with conditionals.
 */
__global__ void game_of_life_step_kernel(const std::uint8_t* __restrict__ grid_in,
                                         std::uint8_t* __restrict__ grid_out,
                                         int grid_dim)
{
    const int x = blockIdx.x * blockDim.x + threadIdx.x;
    const int y = blockIdx.y * blockDim.y + threadIdx.y;

    if (x >= grid_dim || y >= grid_dim) {
        return;
    }

    const int idx = y * grid_dim + x;

    std::uint8_t neighbors = 0;

    // Fast path: interior cells (no boundary checks needed)
    if (x > 0 && x < grid_dim - 1 && y > 0 && y < grid_dim - 1) {
        const int row_stride = grid_dim;
        const std::uint8_t* p = grid_in + idx;

        // Manually unrolled 3x3 neighborhood sum excluding center.
        neighbors =
            p[-row_stride - 1] + p[-row_stride] + p[-row_stride + 1] +
            p[-1]                               + p[+1] +
            p[+row_stride - 1] + p[+row_stride] + p[+row_stride + 1];
    } else {
        // Boundary path: explicitly clamp neighbor accesses to grid bounds.
        const int dim = grid_dim;

        // Row above
        if (y > 0) {
            const int base = (y - 1) * dim;
            if (x > 0) neighbors += grid_in[base + x - 1];
            neighbors += grid_in[base + x];
            if (x + 1 < dim) neighbors += grid_in[base + x + 1];
        }

        // Same row
        const int base = y * dim;
        if (x > 0) neighbors += grid_in[base + x - 1];
        if (x + 1 < dim) neighbors += grid_in[base + x + 1];

        // Row below
        if (y + 1 < dim) {
            const int base2 = (y + 1) * dim;
            if (x > 0) neighbors += grid_in[base2 + x - 1];
            neighbors += grid_in[base2 + x];
            if (x + 1 < dim) neighbors += grid_in[base2 + x + 1];
        }
    }

    const std::uint8_t cell = grid_in[idx];

    // Apply Game of Life rules:
    // - live cell survives iff it has 2 or 3 neighbors
    // - dead cell becomes alive iff it has exactly 3 neighbors
    std::uint8_t next_state =
        (neighbors == 3) | (cell & (neighbors == 2));

    grid_out[idx] = next_state;
}


/*
 * Kernel 3: Pack a dense 1-byte-per-cell grid back into 8x8 bit-packed tiles.
 */
__global__ void pack_tiles_kernel(const std::uint8_t* __restrict__ dense_grid,
                                  std::uint64_t* __restrict__ output,
                                  int grid_dim)
{
    const int tiles_per_row = grid_dim / 8;
    const int num_tiles     = tiles_per_row * tiles_per_row;

    int tile_index = blockIdx.x * blockDim.x + threadIdx.x;
    if (tile_index >= num_tiles) return;

    int tile_y = tile_index / tiles_per_row;
    int tile_x = tile_index % tiles_per_row;

    const int base_x = tile_x * 8;
    const int base_y = tile_y * 8;

    std::uint64_t word = 0;

#pragma unroll
    for (int local_y = 0; local_y < 8; ++local_y) {
        const int global_y   = base_y + local_y;
        const int row_offset = global_y * grid_dim + base_x;

#pragma unroll
        for (int local_x = 0; local_x < 8; ++local_x) {
            const int idx = row_offset + local_x;
            std::uint8_t cell = dense_grid[idx] & 0x1u;

            const int bit_index = local_y * 8 + local_x;
            word |= (static_cast<std::uint64_t>(cell) << bit_index);
        }
    }

    output[tile_index] = word;
}


/*
 * Public API:
 *
 * Execute one step of Conway's Game of Life on a square grid using CUDA.
 *
 * Parameters:
 * - input:  Device pointer to bit-packed input grid.
 * - output: Device pointer to bit-packed output grid.
 * - grid_dimensions: Width/height of the square grid (power of 2).
 *
 * Requirements:
 * - input and output must be allocated with cudaMalloc.
 * - grid_dimensions is a power of 2, > 512, and a multiple of 8.
 *
 * Behavior:
 * - This function:
 *     1) Allocates temporary dense grids on the device.
 *     2) Unpacks the bit-packed input into a dense byte grid.
 *     3) Runs one Game of Life step on the dense grid.
 *     4) Packs the result back into bit-packed tiles in output.
 *     5) Frees the temporary dense grids.
 * - No host-device synchronization (cudaDeviceSynchronize) is performed.
 */
void run_game_of_life(const std::uint64_t* input,
                      std::uint64_t* output,
                      int grid_dimensions)
{
    const int dim        = grid_dimensions;
    const int num_cells  = dim * dim;
    const int tiles_per_row = dim / 8;
    const int num_tiles  = tiles_per_row * tiles_per_row;

    // Allocate temporary dense (1-byte-per-cell) grids on the device.
    std::uint8_t* d_dense_in  = nullptr;
    std::uint8_t* d_dense_out = nullptr;

    cudaMalloc(&d_dense_in,  static_cast<std::size_t>(num_cells) * sizeof(std::uint8_t));
    cudaMalloc(&d_dense_out, static_cast<std::size_t>(num_cells) * sizeof(std::uint8_t));

    // 1) Unpack bit-packed tiles to dense grid.
    {
        const int threads_per_block = 256;
        const int blocks = (num_tiles + threads_per_block - 1) / threads_per_block;
        unpack_tiles_kernel<<<blocks, threads_per_block>>>(input, d_dense_in, dim);
    }

    // 2) Run one Game of Life step on dense grid.
    {
        // Use a 2D launch configuration that favors coalesced accesses.
        dim3 block_dim(32, 8);  // 256 threads per block
        dim3 grid_dim_2d((dim + block_dim.x - 1) / block_dim.x,
                         (dim + block_dim.y - 1) / block_dim.y);

        game_of_life_step_kernel<<<grid_dim_2d, block_dim>>>(d_dense_in, d_dense_out, dim);
    }

    // 3) Pack dense grid back into bit-packed tiles.
    {
        const int threads_per_block = 256;
        const int blocks = (num_tiles + threads_per_block - 1) / threads_per_block;
        pack_tiles_kernel<<<blocks, threads_per_block>>>(d_dense_out, output, dim);
    }

    // Free temporary dense grids.
    cudaFree(d_dense_in);
    cudaFree(d_dense_out);
}

#include <cstdint>
#include <cuda_runtime.h>

/*
 * CUDA implementation of one step of Conway's Game of Life on a bit-packed grid.
 *
 * Layout assumptions:
 * - The grid is square with side length `grid_dimensions`, which is a power of 2 > 512.
 * - Each std::uint64_t encodes an 8×8 tile of cells in row-major order:
 *      bit index = y * 8 + x, where 0 <= x,y < 8
 *      bit 0 corresponds to (x=0,y=0), bit 1 to (1,0), ..., bit 63 to (7,7).
 * - Tiles themselves are laid out row-major:
 *      tile_x = 0..(grid_dimensions/8 - 1)
 *      tile_y = 0..(grid_dimensions/8 - 1)
 *      linear index = tile_y * tiles_per_row + tile_x
 *
 * - All cells outside the global grid are considered dead (0).
 *
 * This kernel assigns one 8×8 tile to each thread. Each thread:
 *   1. Loads the 3×3 neighborhood of tiles (9 uint64_t values) around its tile
 *      into registers; tiles outside the grid are treated as 0.
 *   2. Computes the next state for all 64 cells in its tile, writing a single
 *      uint64_t to the output.
 *
 * The per-cell neighbor counting is split into:
 *   - Interior cells (x,y in 1..6): all neighbors are within the center tile
 *     and can be handled using only the center word.
 *   - Edge cells (cells on the tile border): neighbors may cross tile
 *     boundaries and are handled via a small helper that indexes into the
 *     3×3 tile neighborhood.
 */

/**
 * @brief Fetch the state of a cell given local coordinates relative to the center tile.
 *
 * @param tiles  Array of 9 uint64_t values forming a 3×3 neighborhood of tiles around
 *               the current tile. Layout:
 *                 tiles[0] = top-left      (-1,-1)
 *                 tiles[1] = top           ( 0,-1)
 *                 tiles[2] = top-right     (+1,-1)
 *                 tiles[3] = left          (-1, 0)
 *                 tiles[4] = center        ( 0, 0)
 *                 tiles[5] = right         (+1, 0)
 *                 tiles[6] = bottom-left   (-1,+1)
 *                 tiles[7] = bottom        ( 0,+1)
 *                 tiles[8] = bottom-right  (+1,+1)
 *
 * @param local_x  X coordinate in range [-1,8] relative to the center tile,
 *                 where [0,7] lie within the center tile, -1 is one cell to
 *                 the left, and 8 is one cell to the right.
 * @param local_y  Y coordinate in range [-1,8] relative to the center tile,
 *                 with the same convention as local_x.
 *
 * The function maps (local_x, local_y) into one of the 3×3 tiles and a bit
 * index within that tile, then returns 0 or 1 depending on whether the cell
 * is dead or alive.
 *
 * Tiles outside the global grid have already been set to 0 by the caller, so
 * this function does not need to perform any explicit boundary checks.
 */
__device__ __forceinline__ int getBitFromTiles(const std::uint64_t tiles[9],
                                               int local_x,
                                               int local_y)
{
    // Determine which tile in the 3×3 neighborhood this coordinate falls into.
    // local_x ∈ [-1,8], local_y ∈ [-1,8].
    // Using arithmetic right shift on signed ints:
    //   -1 >> 3 == -1, 0..7 >> 3 == 0, 8 >> 3 == 1.
    int tile_dx = local_x >> 3;  // -1, 0, or 1
    int tile_dy = local_y >> 3;  // -1, 0, or 1

    // Normalize local coordinates into [0,7] within that tile.
    // For 2's complement, (-1 & 7) == 7, (0..7 & 7) == 0..7, (8 & 7) == 0.
    int x = local_x & 7;
    int y = local_y & 7;

    // Compute flat tile index in [0,8].
    int tileIdx = (tile_dy + 1) * 3 + (tile_dx + 1);

    std::uint64_t t = tiles[tileIdx];

    int bitIdx = (y << 3) + x;
    return static_cast<int>((t >> bitIdx) & 1ULL);
}

/**
 * @brief CUDA kernel that advances one step of Conway's Game of Life.
 *
 * @param input            Device pointer to the input grid (bit-packed).
 * @param output           Device pointer to the output grid (bit-packed).
 * @param grid_dimensions  Width/height of the square grid in cells.
 */
__global__ void game_of_life_kernel(const std::uint64_t* __restrict__ input,
                                    std::uint64_t* __restrict__ output,
                                    int grid_dimensions)
{
    const int tilesPerRow = grid_dimensions >> 3;  // grid_dimensions / 8

    // Tile coordinates in tile space.
    const int tile_x = blockIdx.x * blockDim.x + threadIdx.x;
    const int tile_y = blockIdx.y * blockDim.y + threadIdx.y;

    if (tile_x >= tilesPerRow || tile_y >= tilesPerRow)
        return;

    const int idx = tile_y * tilesPerRow + tile_x;

    // Load center tile.
    const std::uint64_t center = input[idx];

    // Load 3×3 neighborhood of tiles into registers.
    // Layout of tiles[] documented in getBitFromTiles().
    std::uint64_t tiles[9];

    tiles[4] = center;  // center tile

    // Top row of tiles (y-1).
    if (tile_y > 0)
    {
        const int idx_top = (tile_y - 1) * tilesPerRow + tile_x;

        tiles[1] = input[idx_top];  // top (0,-1)

        if (tile_x > 0)
            tiles[0] = input[idx_top - 1];  // top-left (-1,-1)
        else
            tiles[0] = 0;

        if (tile_x + 1 < tilesPerRow)
            tiles[2] = input[idx_top + 1];  // top-right (+1,-1)
        else
            tiles[2] = 0;
    }
    else
    {
        // Outside grid: treated as dead.
        tiles[0] = tiles[1] = tiles[2] = 0;
    }

    // Middle row: left and right tiles.
    if (tile_x > 0)
        tiles[3] = input[idx - 1];  // left (-1,0)
    else
        tiles[3] = 0;

    if (tile_x + 1 < tilesPerRow)
        tiles[5] = input[idx + 1];  // right (+1,0)
    else
        tiles[5] = 0;

    // Bottom row of tiles (y+1).
    if (tile_y + 1 < tilesPerRow)
    {
        const int idx_bottom = (tile_y + 1) * tilesPerRow + tile_x;

        tiles[7] = input[idx_bottom];  // bottom (0,+1)

        if (tile_x > 0)
            tiles[6] = input[idx_bottom - 1];  // bottom-left (-1,+1)
        else
            tiles[6] = 0;

        if (tile_x + 1 < tilesPerRow)
            tiles[8] = input[idx_bottom + 1];  // bottom-right (+1,+1)
        else
            tiles[8] = 0;
    }
    else
    {
        tiles[6] = tiles[7] = tiles[8] = 0;
    }

    // Compute next state for this tile.
    std::uint64_t nextTile = 0;

    // First handle interior cells: 1 <= x,y <= 6.
    // All neighbors for these cells lie within the center tile, so we can
    // use simple bit-index arithmetic on `center` only.
#pragma unroll
    for (int ly = 1; ly <= 6; ++ly)
    {
#pragma unroll
        for (int lx = 1; lx <= 6; ++lx)
        {
            const int bitIdx = (ly << 3) + lx;

            int neighborCount = 0;
            neighborCount += (int)((center >> (bitIdx - 9)) & 1ULL);  // NW
            neighborCount += (int)((center >> (bitIdx - 8)) & 1ULL);  // N
            neighborCount += (int)((center >> (bitIdx - 7)) & 1ULL);  // NE
            neighborCount += (int)((center >> (bitIdx - 1)) & 1ULL);  // W
            neighborCount += (int)((center >> (bitIdx + 1)) & 1ULL);  // E
            neighborCount += (int)((center >> (bitIdx + 7)) & 1ULL);  // SW
            neighborCount += (int)((center >> (bitIdx + 8)) & 1ULL);  // S
            neighborCount += (int)((center >> (bitIdx + 9)) & 1ULL);  // SE

            const int isAlive = (int)((center >> bitIdx) & 1ULL);

            // Game of Life rules:
            // - A live cell survives if it has 2 or 3 live neighbors.
            // - A dead cell becomes alive if it has exactly 3 live neighbors.
            const int newState = (neighborCount == 3) | (isAlive & (neighborCount == 2));

            nextTile |= (std::uint64_t)newState << bitIdx;
        }
    }

    // Handle edge cells (border of the 8×8 tile). These may have neighbors
    // in adjacent tiles, so we use getBitFromTiles() to read from the full
    // 3×3 tile neighborhood.
#pragma unroll
    for (int ly = 0; ly < 8; ++ly)
    {
#pragma unroll
        for (int lx = 0; lx < 8; ++lx)
        {
            // Skip interior cells, already processed above.
            if (lx > 0 && lx < 7 && ly > 0 && ly < 7)
                continue;

            int neighborCount = 0;

#pragma unroll
            for (int dy = -1; dy <= 1; ++dy)
            {
#pragma unroll
                for (int dx = -1; dx <= 1; ++dx)
                {
                    if (dx == 0 && dy == 0)
                        continue;

                    neighborCount += getBitFromTiles(tiles, lx + dx, ly + dy);
                }
            }

            const int bitIdx = (ly << 3) + lx;
            const int isAlive = (int)((center >> bitIdx) & 1ULL);
            const int newState = (neighborCount == 3) | (isAlive & (neighborCount == 2));

            nextTile |= (std::uint64_t)newState << bitIdx;
        }
    }

    // Write the updated tile to output.
    output[idx] = nextTile;
}

/**
 * @brief Host-side function to launch one step of the Game of Life.
 *
 * @param input            Device pointer to the input grid (bit-packed).
 * @param output           Device pointer to the output grid (bit-packed).
 * @param grid_dimensions  Width/height of the square grid in cells.
 *
 * Both input and output must be allocated with cudaMalloc and must contain
 * (grid_dimensions/8) * (grid_dimensions/8) elements of std::uint64_t.
 *
 * Any necessary synchronization is expected to be handled by the caller.
 */
void run_game_of_life(const std::uint64_t* input,
                      std::uint64_t* output,
                      int grid_dimensions)
{
    const int tilesPerRow = grid_dimensions >> 3;  // grid_dimensions / 8

    dim3 blockDim(16, 16);
    dim3 gridDim(
        (tilesPerRow + blockDim.x - 1) / blockDim.x,
        (tilesPerRow + blockDim.y - 1) / blockDim.y);

    game_of_life_kernel<<<gridDim, blockDim>>>(input, output, grid_dimensions);
}

```cpp
// CUDA implementation of a single-step Conway's Game of Life on a square grid,
// where the grid is bit-packed into 8×8 tiles stored in std::uint64_t values.
//
// Layout assumptions:
// - The full grid is grid_dimensions × grid_dimensions cells.
// - grid_dimensions is a power of 2, >= 512, and divisible by 8.
// - The grid is partitioned into tiles of size 8×8 cells.
// - Each tile is stored in one std::uint64_t (8 bytes).
// - Tiles are stored in row-major order: tile (tileY, tileX) is at index
//   tileY * tilesPerDim + tileX, where tilesPerDim = grid_dimensions / 8.
// - Within a tile, bits are laid out in row-major order with LSB first:
//   bit index = localY * 8 + localX, where localX, localY ∈ [0,7].
//   - localY = 0 is the top row of the tile
//   - localX = 0 is the leftmost column of the tile
//   - Bit 0 (LSB) is cell (0,0) of the tile, bit 63 is cell (7,7).
//
// Kernel strategy:
// - One thread processes one 8×8 tile.
// - Each thread loads a 3×3 neighborhood of tiles (up to 9 uint64_t values).
//   Tiles that would fall outside the grid are treated as all-dead (value 0).
// - For every cell in the central tile (64 cells), the thread counts the
//   number of alive neighbors by looking up bits in the 3×3 tile neighborhood.
// - The next state is computed using Conway's rules:
//     - Alive cell with <2 or >3 neighbors dies.
//     - Alive cell with 2 or 3 neighbors survives.
//     - Dead cell with exactly 3 neighbors becomes alive.
// - The result for the 8×8 tile is written back as one uint64_t.
//
// Performance considerations:
// - The kernel performs only coalesced global loads/stores and uses registers
//   for all intermediate data. No shared or texture memory is used.
// - Loops over tile coordinates are small and fully unrolled to reduce
//   branching and loop overhead.
// - Neighbor tiles at grid boundaries are zero-filled at load time, so the
//   neighbor-counting logic does not need to handle global boundary checks.

#include <cstdint>
#include <cstddef>
#include <cuda_runtime.h>

////////////////////////////////////////////////////////////////////////////////
// Device kernel
////////////////////////////////////////////////////////////////////////////////

__global__
void game_of_life_kernel(const std::uint64_t* __restrict__ input,
                         std::uint64_t* __restrict__ output,
                         int tilesPerDim)
{
    // Compute tile coordinates for this thread.
    const int tileX = blockIdx.x * blockDim.x + threadIdx.x;
    const int tileY = blockIdx.y * blockDim.y + threadIdx.y;

    if (tileX >= tilesPerDim || tileY >= tilesPerDim) {
        return;
    }

    const std::size_t tileIndex =
        static_cast<std::size_t>(tileY) * static_cast<std::size_t>(tilesPerDim)
        + static_cast<std::size_t>(tileX);

    // Load the 3×3 neighborhood of tiles surrounding the current tile.
    //
    // tiles[ (dy+1)*3 + (dx+1) ] corresponds to the tile at relative
    // offset (dy, dx), where dy, dx ∈ {-1, 0, 1}.
    //
    // Example:
    //   tiles[4] = tiles[(0+1)*3 + (0+1)] = center tile
    //   tiles[1] = tiles[(-1+1)*3 + (0+1)] = tile above
    //   tiles[7] = tiles[(1+1)*3 + (0+1)] = tile below
    //
    // Tiles outside the grid are treated as all-dead (0).
    std::uint64_t tiles[9];

    for (int dy = -1; dy <= 1; ++dy) {
        const int nty = tileY + dy;
        const bool yInBounds = (nty >= 0 && nty < tilesPerDim);

        for (int dx = -1; dx <= 1; ++dx) {
            const int ntx = tileX + dx;

            std::uint64_t val = 0;
            if (yInBounds && ntx >= 0 && ntx < tilesPerDim) {
                const std::size_t nIndex =
                    static_cast<std::size_t>(nty) * static_cast<std::size_t>(tilesPerDim)
                    + static_cast<std::size_t>(ntx);
                val = input[nIndex];
            }

            tiles[(dy + 1) * 3 + (dx + 1)] = val;
        }
    }

    const std::uint64_t centerTile = tiles[4]; // central tile at offset (0,0)

    std::uint64_t nextTile = 0;

    // Iterate over the 8×8 cells within the tile and compute the next state.
    // All loops are unrolled to maximize ILP and reduce control overhead.
    #pragma unroll
    for (int localY = 0; localY < 8; ++localY) {
        const int rowBase = localY * 8; // bit index base for this row

        #pragma unroll
        for (int localX = 0; localX < 8; ++localX) {
            const int selfBitIndex = rowBase + localX;

            const int selfAlive =
                static_cast<int>((centerTile >> selfBitIndex) & 1ull);

            int aliveNeighbors = 0;

            // Sum up alive neighbors over the 3×3 neighborhood.
            #pragma unroll
            for (int offsetY = -1; offsetY <= 1; ++offsetY) {
                const int ny = localY + offsetY;

                // Determine which neighbor tile row this vertical offset falls
                // into and the local Y coordinate inside that tile.
                //
                // ny ∈ [-1, 8]
                // - If ny < 0      -> tileDY = -1, localNY = 7
                // - If 0 <= ny <=7 -> tileDY =  0, localNY = ny
                // - If ny > 7      -> tileDY =  1, localNY = 0
                const int tileDY = (ny < 0) ? -1 : (ny > 7 ? 1 : 0);
                const int localNY = ny & 7; // wrap to [0,7] (since ny is in [-1,8])

                #pragma unroll
                for (int offsetX = -1; offsetX <= 1; ++offsetX) {
                    // Skip the cell itself.
                    if (offsetX == 0 && offsetY == 0) {
                        continue;
                    }

                    const int nx = localX + offsetX;

                    // Determine which neighbor tile column this horizontal offset
                    // falls into and the local X coordinate inside that tile.
                    //
                    // nx ∈ [-1, 8]
                    // - If nx < 0      -> tileDX = -1, localNX = 7
                    // - If 0 <= nx <=7 -> tileDX =  0, localNX = nx
                    // - If nx > 7      -> tileDX =  1, localNX = 0
                    const int tileDX = (nx < 0) ? -1 : (nx > 7 ? 1 : 0);
                    const int localNX = nx & 7; // wrap to [0,7]

                    const int tileIdx = (tileDY + 1) * 3 + (tileDX + 1);
                    const std::uint64_t neighborTile = tiles[tileIdx];

                    const int neighborBitIndex = (localNY << 3) + localNX;

                    aliveNeighbors += static_cast<int>(
                        (neighborTile >> neighborBitIndex) & 1ull
                    );
                }
            }

            // Apply Conway's Game of Life rules:
            //
            // - Any alive cell with fewer than 2 alive neighbors dies.
            // - Any alive cell with 2 or 3 alive neighbors survives.
            // - Any alive cell with more than 3 alive neighbors dies.
            // - Any dead cell with exactly 3 alive neighbors becomes alive.
            //
            // aliveNeighbors ∈ [0,8]
            // selfAlive is 0 or 1.

            if (aliveNeighbors == 3 ||
                (selfAlive && aliveNeighbors == 2)) {
                nextTile |= (std::uint64_t{1} << selfBitIndex);
            }
        }
    }

    output[tileIndex] = nextTile;
}

////////////////////////////////////////////////////////////////////////////////
// Host entry point
////////////////////////////////////////////////////////////////////////////////

void run_game_of_life(const std::uint64_t* input,
                      std::uint64_t* output,
                      int grid_dimensions)
{
    // grid_dimensions is the number of cells per side; each tile is 8×8 cells.
    const int tilesPerDim = grid_dimensions >> 3; // grid_dimensions / 8

    // Thread block configuration: 16×16 threads per block.
    // Each thread handles one 8×8 tile, so the logical tile grid is
    // covered by the CUDA grid formed below.
    const dim3 blockDim(16, 16);
    const dim3 gridDim(
        (tilesPerDim + blockDim.x - 1) / blockDim.x,
        (tilesPerDim + blockDim.y - 1) / blockDim.y
    );

    // Launch kernel. Host-device synchronization and error checking
    // are assumed to be handled by the caller.
    game_of_life_kernel<<<gridDim, blockDim>>>(input, output, tilesPerDim);
}
