#include <cstdint>
#include <cuda_runtime.h>

/*
 * CUDA implementation of a single-step update of Conway's Game of Life
 * on a bit-packed grid.
 *
 * Data layout:
 * - The grid is square with dimensions N x N, where N is a power of 2 (> 512).
 * - Each std::uint64_t word stores 64 consecutive cells in the same row.
 *   Bit 0 (LSB) is the leftmost cell of the 64-cell block, bit 63 the rightmost.
 * - The grid is stored in row-major order: row 0 words, then row 1 words, etc.
 *
 * Execution strategy:
 * - Each CUDA thread processes exactly one 64-bit word (64 cells).
 * - Threads do not interact; no atomics are needed.
 * - For the word at (row, col), the thread loads up to 9 words:
 *     (row-1, col-1), (row-1, col), (row-1, col+1)
 *     (row,   col-1), (row,   col), (row,   col+1)
 *     (row+1, col-1), (row+1, col), (row+1, col+1)
 *   (where out-of-bounds accesses are treated as zero / absent neighbors).
 *
 * Neighborhood computation:
 * - From the three rows (above, current, below) and their adjacent words,
 *   we construct eight 64-bit "direction" bit-planes:
 *     nw, n, ne, w, e, sw, s, se
 *   Each bit position j (0..63) in these words represents the neighbor in
 *   that direction for the cell at bit j in the current word.
 * - Horizontal neighbors (W/E) and diagonal neighbors (NW/NE/SW/SE) are formed
 *   by shifting the row words left/right by 1 bit and patching the bit 0 / 63
 *   using the left/right neighbor words (to avoid cross-bit contamination).
 * - All cells outside the global N x N grid are treated as dead (0).
 *
 * Neighbor counting:
 * - For each bit position (cell), we need the count of 8 neighbors (0..8).
 * - We compute this count for all 64 cells in parallel using bit-sliced
 *   arithmetic:
 *     - Maintain four 64-bit accumulators: ones, twos, fours, eights.
 *       For each bit position j these store the 4-bit binary representation
 *       of the neighbor count at that position:
 *         count[j] = ones[j]*1 + twos[j]*2 + fours[j]*4 + eights[j]*8
 *     - Add each of the eight neighbor bit-planes (nw, n, ne, w, e, sw, s, se)
 *       into the accumulators using ripple-carry binary addition expressed
 *       entirely in bitwise operations. This ensures that each bit position
 *       (cell) is updated independently (no cross-cell carry propagation).
 *
 * Applying the Game of Life rules:
 * - Let center be the current 64-bit word of cell states.
 * - From the accumulators we derive two 64-bit masks:
 *     eq2: bits where neighbor count == 2
 *     eq3: bits where neighbor count == 3
 * - The update rule per cell is:
 *     - If the cell is alive and has 2 or 3 neighbors, it survives.
 *     - If the cell is dead and has exactly 3 neighbors, it becomes alive.
 *   In bitwise form for entire word:
 *     next = eq3 | (eq2 & center)
 *   (eq3 covers both births (dead->alive) and survival of cells with 3 neighbors.
 *    eq2 & center covers survival of cells with exactly 2 neighbors.)
 */

/* 
 * Bit-sliced addition of a single 1-bit "plane" v into the multi-bit
 * neighbor count represented by (ones, twos, fours, eights).
 *
 * Each argument is a 64-bit word. For each bit position j, we treat:
 *   count[j] = ones[j] + 2*twos[j] + 4*fours[j] + 8*eights[j]
 * v[j] is 0 or 1 and we want:
 *   count'[j] = count[j] + v[j]
 *
 * We implement a ripple-carry adder in bit-sliced form:
 * - First add v to ones, generating carry0 into twos.
 * - Add carry0 to twos, generating carry1 into fours.
 * - Add carry1 to fours, generating carry2 into eights.
 * - Add carry2 to eights (no further carry needed since max count is 8).
 */
__device__ __forceinline__
void add_bitplane(std::uint64_t v,
                  std::uint64_t &ones,
                  std::uint64_t &twos,
                  std::uint64_t &fours,
                  std::uint64_t &eights)
{
    // Add v into the least significant bit (ones)
    std::uint64_t carry0 = ones & v;
    ones ^= v;

    // Propagate carry into the 2's bit (twos)
    std::uint64_t carry1 = twos & carry0;
    twos ^= carry0;

    // Propagate carry into the 4's bit (fours)
    std::uint64_t carry2 = fours & carry1;
    fours ^= carry1;

    // Propagate carry into the 8's bit (eights)
    eights ^= carry2;
}

/*
 * Kernel that computes one Game of Life step on a bit-packed grid.
 *
 * Parameters:
 *   input      - pointer to input grid (N x N cells bit-packed into uint64_t)
 *   output     - pointer to output grid (same layout as input)
 *   grid_dim   - N, width and height of the square grid
 */
__global__
void game_of_life_kernel(const std::uint64_t* __restrict__ input,
                         std::uint64_t* __restrict__ output,
                         int grid_dim)
{
    const int words_per_row = grid_dim >> 6;  // N / 64
    const int total_words   = words_per_row * grid_dim;

    const int word_idx = blockDim.x * blockIdx.x + threadIdx.x;
    if (word_idx >= total_words)
        return;

    const int row = word_idx / words_per_row;
    const int col = word_idx - row * words_per_row;

    // Load center word for current row and its horizontal neighbors.
    // For boundary columns, left/right words are treated as zero.
    const std::uint64_t center = input[word_idx];
    std::uint64_t left  = 0;
    std::uint64_t right = 0;

    if (col > 0) {
        left = input[word_idx - 1];
    }
    if (col + 1 < words_per_row) {
        right = input[word_idx + 1];
    }

    // Load words from the row above (if any)
    std::uint64_t above    = 0;
    std::uint64_t above_l  = 0;
    std::uint64_t above_r  = 0;
    if (row > 0) {
        const int above_idx = word_idx - words_per_row;
        above = input[above_idx];
        if (col > 0) {
            above_l = input[above_idx - 1];
        }
        if (col + 1 < words_per_row) {
            above_r = input[above_idx + 1];
        }
    }

    // Load words from the row below (if any)
    std::uint64_t below    = 0;
    std::uint64_t below_l  = 0;
    std::uint64_t below_r  = 0;
    if (row + 1 < grid_dim) {
        const int below_idx = word_idx + words_per_row;
        below = input[below_idx];
        if (col > 0) {
            below_l = input[below_idx - 1];
        }
        if (col + 1 < words_per_row) {
            below_r = input[below_idx + 1];
        }
    }

    // Construct eight neighbor direction bit-planes.
    //
    // Bit mapping convention:
    //   - Bit i (0..63) corresponds to column (col*64 + i).
    //   - For the cell at bit i:
    //       west neighbor is bit (i - 1),
    //       east neighbor is bit (i + 1).
    //
    // Within a word, we obtain these by shifting by ±1. For bit 0 and bit 63,
    // neighbors may cross word boundaries, which we fix using left/right words.
    //
    // 'above', 'center', and 'below' correspond to N, C, S rows, respectively.
    std::uint64_t n  = above;
    std::uint64_t s  = below;
    std::uint64_t w  = center << 1;
    std::uint64_t e  = center >> 1;

    std::uint64_t nw = above << 1;
    std::uint64_t ne = above >> 1;
    std::uint64_t sw = below << 1;
    std::uint64_t se = below >> 1;

    // Patch cross-word neighbors for bit 0 and bit 63.
    if (col > 0) {
        const std::uint64_t left_msb_a = above_l >> 63;
        const std::uint64_t left_msb_c = left     >> 63;
        const std::uint64_t left_msb_b = below_l  >> 63;

        nw |= left_msb_a;  // NW neighbor for bit 0 from above_l bit 63
        w  |= left_msb_c;  // W  neighbor for bit 0 from left     bit 63
        sw |= left_msb_b;  // SW neighbor for bit 0 from below_l  bit 63
    }

    if (col + 1 < words_per_row) {
        const std::uint64_t right_lsb_a = above_r & 1u;
        const std::uint64_t right_lsb_c = right   & 1u;
        const std::uint64_t right_lsb_b = below_r & 1u;

        ne |= right_lsb_a << 63;  // NE neighbor for bit 63 from above_r bit 0
        e  |= right_lsb_c << 63;  // E  neighbor for bit 63 from right   bit 0
        se |= right_lsb_b << 63;  // SE neighbor for bit 63 from below_r bit 0
    }

    // Bit-sliced neighbor count accumulators.
    std::uint64_t ones   = 0;
    std::uint64_t twos   = 0;
    std::uint64_t fours  = 0;
    std::uint64_t eights = 0;

    // Add all eight neighbor direction planes.
    add_bitplane(n,  ones, twos, fours, eights);
    add_bitplane(s,  ones, twos, fours, eights);
    add_bitplane(e,  ones, twos, fours, eights);
    add_bitplane(w,  ones, twos, fours, eights);
    add_bitplane(ne, ones, twos, fours, eights);
    add_bitplane(nw, ones, twos, fours, eights);
    add_bitplane(se, ones, twos, fours, eights);
    add_bitplane(sw, ones, twos, fours, eights);

    // At this point, for each bit position j, the neighbor count is:
    //   neighbors[j] = ones[j] + 2*twos[j] + 4*fours[j] + 8*eights[j]
    // We only need to distinguish exact counts of 2 and 3.
    const std::uint64_t not_ones   = ~ones;
    const std::uint64_t not_fours  = ~fours;
    const std::uint64_t not_eights = ~eights;

    // Mask where neighbor count == 3 (ones=1, twos=1, fours=0, eights=0)
    const std::uint64_t eq3 = ones & twos & not_fours & not_eights;

    // Mask where neighbor count == 2 (ones=0, twos=1, fours=0, eights=0)
    const std::uint64_t eq2 = not_ones & twos & not_fours & not_eights;

    // Game of Life update:
    // new_cell = (neighbors == 3) OR (center == 1 AND neighbors == 2)
    const std::uint64_t next = eq3 | (eq2 & center);

    output[word_idx] = next;
}

/*
 * Host wrapper that launches one Game of Life step on the GPU.
 *
 * Parameters:
 *   input            - device pointer to input grid (bit-packed)
 *   output           - device pointer to output grid (bit-packed)
 *   grid_dimensions  - N, width and height of the square grid
 *
 * Notes:
 * - input and output must already be allocated on the device via cudaMalloc.
 * - This function does not perform any stream or device synchronization;
 *   the caller is responsible for synchronization as needed.
 */
void run_game_of_life(const std::uint64_t* input,
                      std::uint64_t* output,
                      int grid_dimensions)
{
    const int words_per_row = grid_dimensions >> 6;  // grid_dimensions / 64
    const int total_words   = words_per_row * grid_dimensions;

    // Use a reasonably large block size to maximize occupancy while keeping
    // register usage under control on modern data-center GPUs (A100/H100).
    const int block_size = 256;
    const int grid_size  = (total_words + block_size - 1) / block_size;

    game_of_life_kernel<<<grid_size, block_size>>>(input, output, grid_dimensions);
}

#include <cstdint>
#include <cstddef>
#include <cuda_runtime.h>

/*
 * CUDA implementation of one step of Conway's Game of Life on a square grid.
 *
 * Grid representation
 * -------------------
 * - The grid is grid_dimensions x grid_dimensions cells.
 * - Each cell is a single bit: 0 = dead, 1 = alive.
 * - The grid is stored in row-major order, bit-packed into std::uint64_t words.
 *   Each word contains 64 consecutive cells in the same row.
 *   Bit 0 (LSB) corresponds to the leftmost cell within the word,
 *   bit 63 (MSB) to the rightmost.
 *
 * Thread mapping
 * --------------
 * - Each CUDA thread processes exactly one 64-bit word.
 * - The kernel is launched with a 2D grid of thread blocks:
 *       x-dimension over word columns in a row,
 *       y-dimension over rows.
 *
 * Neighborhood handling
 * ---------------------
 * For a given word W at (row, col_word), we need up to 9 words:
 *   Row above:    n_left, n, n_right
 *   Current row:  c_left, c, c_right
 *   Row below:    s_left, s, s_right
 *
 * Border cells: any word outside the valid range is treated as 0 (all dead cells).
 *
 * Within each 64-bit word, we compute the 8 neighbor bitmasks:
 *   W  - left neighbors  (same row)
 *   E  - right neighbors (same row)
 *   N  - above
 *   S  - below
 *   NW - above-left
 *   NE - above-right
 *   SW - below-left
 *   SE - below-right
 *
 * To handle word-boundary neighbors (bit 0 and bit 63), we use shifts with
 * cross-word carry:
 *   - Left neighbor mask:
 *       L(x, left)  = (x << 1) | (left >> 63)
 *   - Right neighbor mask:
 *       R(x, right) = (x >> 1) | ((right & 1ULL) << 63)
 *
 * With bit 0 as the leftmost cell in a word:
 *   - For cell j, its left neighbor is at bit j-1 (or bit 63 of the left word).
 *   - For cell j, its right neighbor is at bit j+1 (or bit 0 of the right word).
 *
 * Neighbor counting (bit-parallel)
 * --------------------------------
 * We have 8 bitmasks (NW, N, NE, W, E, SW, S, SE). For each bit position,
 * we must count how many of these 8 masks have a '1' at that position.
 *
 * Instead of counting per cell, we use a bit-sliced counter:
 *   - Maintain three 64-bit words: count0, count1, count2.
 *   - For each bit position i:
 *       (count2[i], count1[i], count0[i]) is the 3-bit count of neighbors
 *       at that position, modulo 8.
 *
 * Since each cell has at most 8 neighbors, counts are in [0, 8]. Representing
 * the count modulo 8 is sufficient, because:
 *   - The Game of Life rules depend only on whether the count is 2 or 3.
 *   - 2 (010b) and 3 (011b) are distinct modulo 8.
 *   - Count 8 (1000b) becomes 000b modulo 8, which is fine because cells with
 *     8 neighbors are not supposed to survive or be born (they behave like 0).
 *
 * To add a neighbor mask 'm' to the counters, we perform a 3-bit increment
 * controlled by 'm' for each bit position:
 *   if m[i] == 1: count[i] = (count[i] + 1) mod 8
 *   else:         count[i] unchanged
 *
 * This is implemented using bitwise logic (no integer addition, so no cross-bit
 * carries) via:
 *   carry1 = count0 & m;
 *   count0 ^= m;
 *   carry2 = count1 & carry1;
 *   count1 ^= carry1;
 *   count2 ^= carry2;
 *
 * After processing all 8 neighbor masks, for each bit:
 *   - neighbor_count == 3  if  (count2 == 0, count1 == 1, count0 == 1)
 *   - neighbor_count == 2  if  (count2 == 0, count1 == 1, count0 == 0)
 *
 * Thus:
 *   neighbors_eq_3 =  count0 &  count1 & ~count2
 *   neighbors_eq_2 = ~count0 &  count1 & ~count2
 *
 * Game of Life transition
 * ------------------------
 * Let 'c' be the current word (bitmask of alive cells in this word).
 * The next state is:
 *   next = neighbors_eq_3 | (c & neighbors_eq_2)
 *        = born            | survived
 *
 * Boundary conditions
 * -------------------
 * All cells outside the grid are considered dead. We implement this by setting
 * neighbor words (n, s, left/right variants) to zero when the corresponding
 * row/column index is out of bounds, and by not injecting any carry from those
 * words during shift-with-carry operations.
 */

////////////////////////////////////////////////////////////////////////////////
// Device helper functions
////////////////////////////////////////////////////////////////////////////////

/**
 * Shift a word left by one bit, inserting bit 63 of 'left' into bit 0.
 *
 * This implements "left neighbor" mapping for bit-packed rows:
 *   - For bits 1..63: new_bit[j] = center_bit[j-1]
 *   - For bit 0:      new_bit[0] = left_bit[63]
 */
__device__ __forceinline__
std::uint64_t shift_left_with_carry(std::uint64_t center, std::uint64_t left)
{
    return (center << 1) | (left >> 63);
}

/**
 * Shift a word right by one bit, inserting bit 0 of 'right' into bit 63.
 *
 * This implements "right neighbor" mapping for bit-packed rows:
 *   - For bits 0..62: new_bit[j] = center_bit[j+1]
 *   - For bit 63:     new_bit[63] = right_bit[0]
 */
__device__ __forceinline__
std::uint64_t shift_right_with_carry(std::uint64_t center, std::uint64_t right)
{
    return (center >> 1) | ((right & 1ULL) << 63);
}

/**
 * Add one neighbor bitmask 'mask' to the bit-sliced counters (count2:count1:count0),
 * performing a modulo-8 increment at every bit position where 'mask' has a 1.
 *
 * For each bit position i:
 *   if mask[i] == 1:
 *        (count2[i], count1[i], count0[i]) := (count2[i], count1[i], count0[i]) + 1 (mod 8)
 *   else:
 *        unchanged
 *
 * Implemented entirely with bitwise operations, so there are no carries between
 * different bit positions.
 */
__device__ __forceinline__
void add_neighbor_mask(std::uint64_t mask,
                       std::uint64_t &count0,
                       std::uint64_t &count1,
                       std::uint64_t &count2)
{
    // First bit (LSB of the 3-bit counter)
    std::uint64_t carry1 = count0 & mask;  // positions where count0 and mask are both 1
    count0 ^= mask;                        // add mask to LSB (mod 2)

    // Second bit
    std::uint64_t carry2 = count1 & carry1; // carry from adding carry1 to count1
    count1 ^= carry1;                       // add carry1 to second bit (mod 2)

    // Third bit
    count2 ^= carry2;                      // add carry2 to third bit (mod 2), ignoring overflow
}

////////////////////////////////////////////////////////////////////////////////
// Kernel
////////////////////////////////////////////////////////////////////////////////

/**
 * Kernel that computes one Game of Life step on a bit-packed grid.
 *
 * Parameters:
 *   input        - pointer to input grid (device memory), bit-packed in uint64_t
 *   output       - pointer to output grid (device memory), bit-packed in uint64_t
 *   grid_dim     - number of cells per row/column (grid is grid_dim x grid_dim)
 *   words_per_row- number of 64-bit words per row (grid_dim / 64)
 */
__global__
void game_of_life_kernel(const std::uint64_t* __restrict__ input,
                         std::uint64_t* __restrict__ output,
                         int grid_dim,
                         int words_per_row)
{
    // Column index in units of 64-cell words
    int col_word = blockIdx.x * blockDim.x + threadIdx.x;
    // Row index (in cells)
    int row = blockIdx.y * blockDim.y + threadIdx.y;

    if (row >= grid_dim || col_word >= words_per_row)
        return;

    // Row offset in number of 64-bit words
    std::size_t row_offset = static_cast<std::size_t>(row) * static_cast<std::size_t>(words_per_row);
    const std::uint64_t* row_ptr = input + row_offset;

    // Current word (central)
    std::uint64_t c = row_ptr[col_word];

    // Neighbor words in the same row
    std::uint64_t c_left  = 0;
    std::uint64_t c_right = 0;
    if (col_word > 0)
        c_left = row_ptr[col_word - 1];
    if (col_word + 1 < words_per_row)
        c_right = row_ptr[col_word + 1];

    // Neighbor words in the row above
    std::uint64_t n      = 0;
    std::uint64_t n_left = 0;
    std::uint64_t n_right= 0;
    if (row > 0) {
        std::size_t row_above_offset = static_cast<std::size_t>(row - 1) * static_cast<std::size_t>(words_per_row);
        const std::uint64_t* row_above = input + row_above_offset;
        n = row_above[col_word];
        if (col_word > 0)
            n_left = row_above[col_word - 1];
        if (col_word + 1 < words_per_row)
            n_right = row_above[col_word + 1];
    }

    // Neighbor words in the row below
    std::uint64_t s      = 0;
    std::uint64_t s_left = 0;
    std::uint64_t s_right= 0;
    if (row + 1 < grid_dim) {
        std::size_t row_below_offset = static_cast<std::size_t>(row + 1) * static_cast<std::size_t>(words_per_row);
        const std::uint64_t* row_below = input + row_below_offset;
        s = row_below[col_word];
        if (col_word > 0)
            s_left = row_below[col_word - 1];
        if (col_word + 1 < words_per_row)
            s_right = row_below[col_word + 1];
    }

    // Compute the eight neighbor masks using shifts with cross-word carries.
    // Horizontal neighbors in current row
    std::uint64_t W  = shift_left_with_carry(c, c_left);   // left neighbors
    std::uint64_t E  = shift_right_with_carry(c, c_right); // right neighbors

    // Vertical neighbors
    std::uint64_t N  = n; // above
    std::uint64_t S  = s; // below

    // Diagonal neighbors
    std::uint64_t NW = shift_left_with_carry(n, n_left);    // above-left
    std::uint64_t NE = shift_right_with_carry(n, n_right);  // above-right
    std::uint64_t SW = shift_left_with_carry(s, s_left);    // below-left
    std::uint64_t SE = shift_right_with_carry(s, s_right);  // below-right

    // Bit-sliced neighbor count accumulators (modulo 8)
    std::uint64_t count0 = 0; // least significant bit
    std::uint64_t count1 = 0;
    std::uint64_t count2 = 0;

    // Add the eight neighbor masks to the counters
    add_neighbor_mask(NW, count0, count1, count2);
    add_neighbor_mask(N,  count0, count1, count2);
    add_neighbor_mask(NE, count0, count1, count2);
    add_neighbor_mask(W,  count0, count1, count2);
    add_neighbor_mask(E,  count0, count1, count2);
    add_neighbor_mask(SW, count0, count1, count2);
    add_neighbor_mask(S,  count0, count1, count2);
    add_neighbor_mask(SE, count0, count1, count2);

    // Determine where neighbor_count == 3 and neighbor_count == 2
    std::uint64_t neighbors_eq_3 =  count0 &  count1 & ~count2;       // 011b
    std::uint64_t neighbors_eq_2 = (~count0) &  count1 & ~count2;     // 010b

    // Apply Conway's Game of Life rules:
    // - A dead cell with exactly 3 neighbors becomes alive.
    // - A live cell with 2 or 3 neighbors survives.
    //   => new = (neighbors == 3) OR (alive & neighbors == 2)
    std::uint64_t next = neighbors_eq_3 | (c & neighbors_eq_2);

    // Store the result
    output[row_offset + static_cast<std::size_t>(col_word)] = next;
}

////////////////////////////////////////////////////////////////////////////////
// Host function
////////////////////////////////////////////////////////////////////////////////

/**
 * Host function that launches the CUDA kernel to compute one step of
 * Conway's Game of Life on a bit-packed grid.
 *
 * Parameters:
 *   input           - device pointer to input grid (bit-packed uint64_t)
 *   output          - device pointer to output grid (bit-packed uint64_t)
 *   grid_dimensions - number of cells per row/column (grid_dimensions x grid_dimensions)
 *
 * Notes:
 *   - 'input' and 'output' must be allocated with cudaMalloc and must not overlap.
 *   - No host-device synchronization is performed here; the caller is responsible
 *     for any necessary synchronization (e.g., cudaDeviceSynchronize).
 */
void run_game_of_life(const std::uint64_t* input,
                      std::uint64_t* output,
                      int grid_dimensions)
{
    // Each row has grid_dimensions cells, packed into 64-bit words.
    // grid_dimensions is guaranteed to be a power of 2, so this is exact.
    int words_per_row = grid_dimensions >> 6; // divide by 64

    // Choose a reasonably sized block for modern NVIDIA GPUs.
    // 32 x 8 = 256 threads per block.
    constexpr int BLOCK_X = 32;
    constexpr int BLOCK_Y = 8;

    dim3 block_dim(BLOCK_X, BLOCK_Y);
    dim3 grid_dim(
        (words_per_row   + BLOCK_X - 1) / BLOCK_X,
        (grid_dimensions + BLOCK_Y - 1) / BLOCK_Y
    );

    game_of_life_kernel<<<grid_dim, block_dim>>>(input, output,
                                                 grid_dimensions,
                                                 words_per_row);
}

