#include <cstdint>
#include <cuda_runtime.h>

/*
 * CUDA implementation of one step of Conway's Game of Life on a square grid.
 *
 * - The grid is grid_dimensions x grid_dimensions cells, where each cell is
 *   encoded as a single bit inside a std::uint64_t word.
 * - Each word encodes 64 consecutive cells in a row (bit 0 = leftmost cell
 *   in that word, bit 63 = rightmost).
 * - input/output point to device memory allocated via cudaMalloc.
 * - Each CUDA thread processes exactly one 64-bit word (64 cells).
 *
 * Neighbor counting is done in bit-parallel fashion:
 *   - For each word, we construct 64-bit masks corresponding to the 8
 *     neighbor directions (N, S, E, W, NE, NW, SE, SW).
 *   - We then accumulate these eight bitplanes into three bitplanes
 *     (ones, twos, fours) that represent a 3-bit counter (0..7) per cell.
 *   - This uses bit-sliced full-adder logic, implemented with simple
 *     bitwise operations (XOR and AND) and no cross-bit carries.
 *   - Finally, we derive masks for neighbor counts of exactly 2 or 3 and
 *     apply the Game of Life rules in parallel for all 64 cells.
 */

/**
 * @brief Add a 1-bit-per-cell bitplane into a 3-bit-per-cell counter.
 *
 * For each bit position i, (ones[i], twos[i], fours[i]) form a 3-bit integer
 * in binary: count = ones + 2*twos + 4*fours (mod 8).
 * This function performs:
 *
 *     count_i = count_i + bit_i   (for all i in parallel)
 *
 * using standard ripple-carry adder logic, but applied independently to each
 * bit position via bitwise operations:
 *   - bit 0 (ones) is updated by XOR with the new bit.
 *   - The carry from bit 0 propagates into bit 1 (twos).
 *   - The carry from bit 1 propagates into bit 2 (fours).
 *
 * Carry out from bit 2 (i.e., transitioning from 7 to 8) is discarded, which
 * is equivalent to addition modulo 8. Since we only need to distinguish
 * neighbor counts 0..7 and 8 is irrelevant to "==2" or "==3", this is safe.
 */
__device__ __forceinline__
void add_neighbor_bitplane(std::uint64_t bits,
                           std::uint64_t &ones,
                           std::uint64_t &twos,
                           std::uint64_t &fours)
{
    // Full-adder bit 0: (ones, bits) -> new ones and carry into twos.
    std::uint64_t carry01 = ones & bits;   // majority(ones, bits, 0)
    ones ^= bits;                          // sum bit (ones XOR bits)

    // Full-adder bit 1: (twos, carry01) -> new twos and carry into fours.
    std::uint64_t carry12 = twos & carry01;
    twos ^= carry01;

    // Full-adder bit 2: (fours, carry12) -> new fours (carry to bit 3 ignored).
    fours ^= carry12;
}

/**
 * @brief CUDA kernel: compute one Game of Life step for a bit-packed grid.
 *
 * Each thread processes one 64-bit word corresponding to 64 cells of a row.
 */
__global__
void game_of_life_kernel(const std::uint64_t* __restrict__ input,
                         std::uint64_t* __restrict__ output,
                         int grid_dim,
                         int words_per_row,
                         int words_per_row_log2,
                         int total_words)
{
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= total_words) {
        return;
    }

    const int max_row = grid_dim - 1;
    const int max_col = words_per_row - 1;

    // Decode (row, colWord) from linear index.
    // words_per_row is a power of two, so we can replace division/modulo
    // by a right shift and a bitmask.
    const int row = idx >> words_per_row_log2;
    const int col = idx & (words_per_row - 1);

    const std::uint64_t center = input[idx];

    // Load neighbor words where they exist; cells outside the grid are dead.
    std::uint64_t north        = 0;
    std::uint64_t south        = 0;
    std::uint64_t west_word    = 0;
    std::uint64_t east_word    = 0;
    std::uint64_t north_west_w = 0;
    std::uint64_t north_east_w = 0;
    std::uint64_t south_west_w = 0;
    std::uint64_t south_east_w = 0;

    if (row > 0) {
        int idx_north = idx - words_per_row;
        north = input[idx_north];
        if (col > 0) {
            north_west_w = input[idx_north - 1];
        }
        if (col < max_col) {
            north_east_w = input[idx_north + 1];
        }
    }

    if (row < max_row) {
        int idx_south = idx + words_per_row;
        south = input[idx_south];
        if (col > 0) {
            south_west_w = input[idx_south - 1];
        }
        if (col < max_col) {
            south_east_w = input[idx_south + 1];
        }
    }

    if (col > 0) {
        west_word = input[idx - 1];
    }
    if (col < max_col) {
        east_word = input[idx + 1];
    }

    // Build the eight neighbor direction masks (bitplanes).
    // For any given bit position b in "center":
    //   - N/S neighbors are at bit b in the north/south words.
    //   - W neighbor is at bit (b-1) or bit 63 of the word to the left
    //     when b == 0.
    //   - E neighbor is at bit (b+1) or bit 0 of the word to the right
    //     when b == 63.
    // Similar logic applies for diagonal neighbors using the appropriate
    // neighbor words above/below and left/right of the current word.
    const std::uint64_t n  = north;
    const std::uint64_t s  = south;

    const std::uint64_t w  = (center >> 1) | (west_word << 63);
    const std::uint64_t e  = (center << 1) | (east_word >> 63);

    const std::uint64_t nw = (north >> 1) | (north_west_w << 63);
    const std::uint64_t ne = (north << 1) | (north_east_w >> 63);
    const std::uint64_t sw = (south >> 1) | (south_west_w << 63);
    const std::uint64_t se = (south << 1) | (south_east_w >> 63);

    // Accumulate neighbor counts with bit-sliced 3-bit counters.
    std::uint64_t ones  = 0;
    std::uint64_t twos  = 0;
    std::uint64_t fours = 0;

    add_neighbor_bitplane(n,  ones, twos, fours);
    add_neighbor_bitplane(s,  ones, twos, fours);
    add_neighbor_bitplane(e,  ones, twos, fours);
    add_neighbor_bitplane(w,  ones, twos, fours);
    add_neighbor_bitplane(ne, ones, twos, fours);
    add_neighbor_bitplane(nw, ones, twos, fours);
    add_neighbor_bitplane(se, ones, twos, fours);
    add_neighbor_bitplane(sw, ones, twos, fours);

    // For each bit position:
    //   neighbor_count = ones + 2*twos + 4*fours  (mod 8)
    //
    // We derive masks for counts equal to 2 or 3. Using binary:
    //   count == 3  => (fours,twos,ones) == 0b011
    //   count == 2  => (fours,twos,ones) == 0b010
    const std::uint64_t not_fours   = ~fours;
    const std::uint64_t count_eq_3  = not_fours & twos &  ones;     // 0b011
    const std::uint64_t count_eq_2  = not_fours & twos & (~ones);   // 0b010

    // Game of Life update rule (per bit):
    //   new_state = (neighbor_count == 3) OR (alive & neighbor_count == 2)
    const std::uint64_t next = count_eq_3 | (center & count_eq_2);

    output[idx] = next;
}

/**
 * @brief Host wrapper to run one Game of Life step on the GPU.
 *
 * @param input           Device pointer to input grid (bit-packed).
 * @param output          Device pointer to output grid (bit-packed).
 * @param grid_dimensions Width and height of the square grid (power of 2).
 *
 * Both input and output must point to arrays of std::uint64_t large enough
 * to store grid_dimensions * grid_dimensions bits, i.e.:
 *
 *   total_words = (grid_dimensions * grid_dimensions) / 64
 *
 * No device synchronization is performed here; the caller is responsible
 * for any required cudaDeviceSynchronize or stream management.
 */
void run_game_of_life(const std::uint64_t* input,
                      std::uint64_t* output,
                      int grid_dimensions)
{
    // Each row contains grid_dimensions cells, i.e., grid_dimensions / 64 words.
    const int words_per_row = grid_dimensions >> 6;  // grid_dimensions / 64
    const int total_words   = words_per_row * grid_dimensions;

    // words_per_row is a power of two since grid_dimensions is a power of two.
    int words_per_row_log2 = 0;
    int tmp = words_per_row;
    while (tmp > 1) {
        tmp >>= 1;
        ++words_per_row_log2;
    }

    // One thread per 64-cell word.
    const int block_size = 256;
    const int grid_size  = (total_words + block_size - 1) / block_size;

    game_of_life_kernel<<<grid_size, block_size>>>(
        input,
        output,
        grid_dimensions,
        words_per_row,
        words_per_row_log2,
        total_words
    );
}

#include <cstdint>
#include <cstddef>
#include <cuda_runtime.h>

/*
 * CUDA implementation of one step of Conway's Game of Life on a bit-packed grid.
 *
 * Grid layout:
 *   - The grid is square: grid_dimensions x grid_dimensions cells.
 *   - Each 64-bit word encodes 64 consecutive cells in a row.
 *   - Words are stored in row-major order.
 *   - Bit i (0 <= i < 64) of word w corresponds to column (w * 64 + i) in that row.
 *
 * Each CUDA thread processes one 64-bit word (i.e., 64 cells) and computes their next
 * generation states using bit-parallel logic with full adders.
 *
 * Neighbor counting:
 *   - For each word, we construct 8 64-bit masks corresponding to the 8 neighbor
 *     directions (N, S, E, W, NE, NW, SE, SW), aligned so that bit k of each mask
 *     is the neighbor of bit k in the current word.
 *   - Horizontal neighbors (W/E) and diagonal neighbors (NW/NE/SW/SE) are built
 *     using bit shifts and cross-word contributions from the left/right words.
 *   - Out-of-bounds neighbors (outside the grid) are treated as dead by using zero.
 *
 *   - We then add these eight 1-bit-per-cell masks using a tree of 3-input full adders:
 *
 *       Given 3 one-bit inputs a, b, c:
 *         sum  = a XOR b XOR c          (least significant bit of their sum)
 *         carry= majority(a,b,c)        (second bit of their sum)
 *
 *       For 8 neighbor masks b0..b7:
 *         1) Group into three triplets:
 *              G0 = (b0, b1, b2)
 *              G1 = (b3, b4, b5)
 *              G2 = (b6, b7, 0)
 *            Each group yields a 2-bit sum (s_i, t_i), representing 0..3.
 *
 *         2) Sum the three group results:
 *              A = s0 + s1 + s2   (via full adder)
 *              B = t0 + t1 + t2   (via full adder)
 *
 *            Write:
 *              A = As + 2*At
 *              B = Bs + 2*Bt
 *
 *            Total neighbor count:
 *              count = A + 2*B
 *                    = As + 2*At + 2*Bs + 4*Bt
 *                    = As + 2*(At + Bs) + 4*Bt
 *
 *         3) Let M = At + Bs (via full adder):
 *              M = Ms + 2*Mt
 *
 *            Then:
 *              count = As + 2*Ms + 4*(Mt + Bt)
 *
 *         4) Interpreting count modulo 8 (we don't need the bit for 8 neighbors):
 *              bit0 (LSB) = As
 *              bit1       = Ms
 *              bit2       = Mt XOR Bt   (since 4*(Mt+Bt) contributes to bit2, with
 *                                         overflow to 8 ignored)
 *
 *       So we obtain three bit-planes (c0,c1,c2) giving the neighbor count modulo 8.
 *       Since there are at most 8 neighbors, modulo-8 encoding is identical to
 *       the true count for values 0..7; 8 maps to 0, which does not equal 2 or 3,
 *       so tests for "exactly 2" and "exactly 3" remain correct.
 *
 * Game of Life rules:
 *   - Let alive be the mask of currently alive cells in the word.
 *   - From (c0,c1,c2), define:
 *       eq2 = (count == 2) = ~c2 &  c1 & ~c0
 *       eq3 = (count == 3) = ~c2 &  c1 &  c0
 *
 *   - Next state:
 *       survive = alive & (eq2 | eq3)
 *       birth   = ~alive & eq3
 *       next    = survive | birth
 */

/* 3-input full adder for 64-bit bitplanes.
 * For each bit position, it adds a, b, c (each 0 or 1) and produces:
 *   sum   = (a + b + c) & 1
 *   carry = ((a + b + c) >> 1) & 1
 * Using:
 *   sum   = a XOR b XOR c
 *   carry = (a & b) | (a & c) | (b & c)   // majority function
 */
__device__ __forceinline__
void full_adder3(std::uint64_t a,
                 std::uint64_t b,
                 std::uint64_t c,
                 std::uint64_t &sum,
                 std::uint64_t &carry)
{
    sum   = a ^ b ^ c;
    carry = (a & b) | (a & c) | (b & c);
}

/* Sum eight 1-bit-per-cell neighbor masks using a tree of full adders.
 * Inputs:
 *   b0..b7 : eight 64-bit masks for neighbor directions
 * Outputs:
 *   c0, c1, c2 : bitplanes of neighbor counts (modulo 8)
 *                count = c0 + 2*c1 + 4*c2
 */
__device__ __forceinline__
void neighbor_count_8way(std::uint64_t b0, std::uint64_t b1,
                         std::uint64_t b2, std::uint64_t b3,
                         std::uint64_t b4, std::uint64_t b5,
                         std::uint64_t b6, std::uint64_t b7,
                         std::uint64_t &c0, std::uint64_t &c1, std::uint64_t &c2)
{
    // First level: three groups of three bits (last group padded with 0)
    std::uint64_t s0, t0;
    std::uint64_t s1, t1;
    std::uint64_t s2, t2;

    full_adder3(b0, b1, b2, s0, t0);   // group 0
    full_adder3(b3, b4, b5, s1, t1);   // group 1
    full_adder3(b6, b7, 0,  s2, t2);   // group 2 (padded)

    // Second level: sum the s* bits -> A, and the t* bits -> B
    std::uint64_t As, At;
    std::uint64_t Bs, Bt;

    full_adder3(s0, t0, s1, As, At);    // This is arbitrary; to strictly follow
                                        // the derivation, we should do:
                                        // full_adder3(s0, s1, s2, As, At);
                                        // full_adder3(t0, t1, t2, Bs, Bt);
                                        // but the mix of s and t would be wrong.
    // Correct: follow the derivation strictly
    full_adder3(s0, s1, s2, As, At);    // A = s0 + s1 + s2
    full_adder3(t0, t1, t2, Bs, Bt);    // B = t0 + t1 + t2

    // Third level: M = At + Bs
    std::uint64_t Ms, Mt;
    full_adder3(At, Bs, 0, Ms, Mt);

    // Final neighbor count bits (modulo 8):
    //   bit0 = As
    //   bit1 = Ms
    //   bit2 = Mt XOR Bt
    c0 = As;
    c1 = Ms;
    c2 = Mt ^ Bt;
}

/* Corrected neighbor_count_8way: the above function accidentally mixed s and t
 * in an intermediate (dead) computation before the correct one. To avoid any
 * confusion, we redefine it cleanly here and rely on this version only.
 */
__device__ __forceinline__
void neighbor_count_8way_correct(std::uint64_t b0, std::uint64_t b1,
                                 std::uint64_t b2, std::uint64_t b3,
                                 std::uint64_t b4, std::uint64_t b5,
                                 std::uint64_t b6, std::uint64_t b7,
                                 std::uint64_t &c0, std::uint64_t &c1, std::uint64_t &c2)
{
    std::uint64_t s0, t0;
    std::uint64_t s1, t1;
    std::uint64_t s2, t2;

    // Group 0: b0, b1, b2
    full_adder3(b0, b1, b2, s0, t0);

    // Group 1: b3, b4, b5
    full_adder3(b3, b4, b5, s1, t1);

    // Group 2: b6, b7, 0
    full_adder3(b6, b7, 0,  s2, t2);

    // Sum s0 + s1 + s2 => A = As + 2*At
    std::uint64_t As, At;
    full_adder3(s0, s1, s2, As, At);

    // Sum t0 + t1 + t2 => B = Bs + 2*Bt
    std::uint64_t Bs, Bt;
    full_adder3(t0, t1, t2, Bs, Bt);

    // M = At + Bs => M = Ms + 2*Mt
    std::uint64_t Ms, Mt;
    full_adder3(At, Bs, 0, Ms, Mt);

    // count = As + 2*Ms + 4*(Mt + Bt)  (modulo 8)
    c0 = As;
    c1 = Ms;
    c2 = Mt ^ Bt;
}

/*
 * CUDA kernel: compute one Game of Life step on a bit-packed grid.
 *
 * Parameters:
 *   input          : device pointer to input grid (bit-packed uint64_t words)
 *   output         : device pointer to output grid (same layout as input)
 *   grid_dim       : width/height of square grid (power of 2)
 *   words_per_row  : number of 64-bit words per row (grid_dim / 64)
 *   row_shift      : log2(words_per_row), since words_per_row is a power of 2
 *   total_words    : total number of 64-bit words (words_per_row * grid_dim)
 *
 * Each thread processes one word at index 'idx'.
 */
__global__
void game_of_life_kernel(const std::uint64_t* __restrict__ input,
                         std::uint64_t* __restrict__ output,
                         int grid_dim,
                         int words_per_row,
                         int row_shift,
                         std::size_t total_words)
{
    std::size_t idx = static_cast<std::size_t>(blockIdx.x) * blockDim.x +
                      static_cast<std::size_t>(threadIdx.x);
    if (idx >= total_words)
        return;

    // Compute row and column in word space:
    //   row = idx / words_per_row
    //   col = idx % words_per_row
    // Since words_per_row is power-of-two, we can use shifts/masks.
    int row = static_cast<int>(idx >> row_shift);
    int col = static_cast<int>(idx & static_cast<std::size_t>(words_per_row - 1));

    const bool has_north = (row > 0);
    const bool has_south = (row + 1 < grid_dim);
    const bool has_west  = (col > 0);
    const bool has_east  = (col + 1 < words_per_row);

    // Load the central word and its immediate left/right neighbors in the same row.
    const std::uint64_t self   = input[idx];
    const std::uint64_t selfL  = has_west ? input[idx - 1] : 0ull;
    const std::uint64_t selfR  = has_east ? input[idx + 1] : 0ull;

    // Load words from the row above (north) and below (south), including left/right.
    std::uint64_t northC = 0ull, northL = 0ull, northR = 0ull;
    std::uint64_t southC = 0ull, southL = 0ull, southR = 0ull;

    if (has_north) {
        std::size_t baseN = idx - static_cast<std::size_t>(words_per_row);
        northC = input[baseN];
        northL = has_west ? input[baseN - 1] : 0ull;
        northR = has_east ? input[baseN + 1] : 0ull;
    }

    if (has_south) {
        std::size_t baseS = idx + static_cast<std::size_t>(words_per_row);
        southC = input[baseS];
        southL = has_west ? input[baseS - 1] : 0ull;
        southR = has_east ? input[baseS + 1] : 0ull;
    }

    // Construct aligned neighbor bitmasks for the 8 directions.
    //
    // For each central bit position k in [0,63]:
    //   W[k] = cell at (row, col_bit-1)
    //   E[k] = cell at (row, col_bit+1)
    //   N[k] = cell at (row-1, col_bit)
    //   S[k] = cell at (row+1, col_bit)
    //   NW[k]= cell at (row-1, col_bit-1)
    //   NE[k]= cell at (row-1, col_bit+1)
    //   SW[k]= cell at (row+1, col_bit-1)
    //   SE[k]= cell at (row+1, col_bit+1)
    //
    // Horizontal neighbors need cross-word contributions for bit 0 and bit 63.
    const std::uint64_t W  = (self << 1) | (selfL >> 63);
    const std::uint64_t E  = (self >> 1) | (selfR << 63);
    const std::uint64_t N  = northC;
    const std::uint64_t S  = southC;

    const std::uint64_t NW = (northC << 1) | (northL >> 63);
    const std::uint64_t NE = (northC >> 1) | (northR << 63);
    const std::uint64_t SW = (southC << 1) | (southL >> 63);
    const std::uint64_t SE = (southC >> 1) | (southR << 63);

    // Count neighbors using bit-parallel full-adder logic.
    std::uint64_t c0, c1, c2;
    neighbor_count_8way_correct(W, E, N, S, NW, NE, SW, SE, c0, c1, c2);

    // Compute masks for "neighbor count == 2" and "neighbor count == 3".
    const std::uint64_t n1 = c0; // bit 0 of count
    const std::uint64_t n2 = c1; // bit 1 of count
    const std::uint64_t n4 = c2; // bit 2 of count

    const std::uint64_t eq2 = (~n4) &  n2  & (~n1); // 010b
    const std::uint64_t eq3 = (~n4) &  n2  &  n1;   // 011b

    // Apply Game of Life rules.
    const std::uint64_t alive   = self;
    const std::uint64_t survive = alive & (eq2 | eq3); // alive with 2 or 3 neighbors
    const std::uint64_t birth   = (~alive) & eq3;      // dead with exactly 3 neighbors
    const std::uint64_t next    = survive | birth;

    // Store result.
    output[idx] = next;
}

/*
 * Host function to launch one Game of Life step.
 *
 * Parameters:
 *   input           : device pointer to input bit-packed grid (cudaMalloc'ed)
 *   output          : device pointer to output bit-packed grid (cudaMalloc'ed)
 *   grid_dimensions : width/height of the square grid; power of 2 (> 512)
 *
 * Notes:
 *   - This function performs only device-side work; no host-device synchronization
 *     is done here. The caller is responsible for synchronization if needed.
 *   - Shared or texture memory is not used, as per the problem constraints.
 */
void run_game_of_life(const std::uint64_t* input,
                      std::uint64_t* output,
                      int grid_dimensions)
{
    // Each 64-bit word encodes 64 cells.
    constexpr int BITS_PER_WORD = 64;

    // Number of 64-bit words per row (grid_dimensions is a power of 2, >= 512).
    const int words_per_row = grid_dimensions / BITS_PER_WORD;

    // Compute log2(words_per_row) for efficient row/column computation in the kernel.
    int row_shift = 0;
    int tmp = words_per_row;
    while (tmp > 1) {
        tmp >>= 1;
        ++row_shift;
    }

    const std::size_t total_words =
        static_cast<std::size_t>(words_per_row) *
        static_cast<std::size_t>(grid_dimensions);

    // Choose a reasonable block size; 256 threads per block is a good default.
    constexpr int BLOCK_SIZE = 256;
    const std::size_t num_blocks =
        (total_words + BLOCK_SIZE - 1) / BLOCK_SIZE;

    dim3 block_dim(BLOCK_SIZE, 1, 1);
    dim3 grid_dim(num_blocks, 1, 1);

    game_of_life_kernel<<<grid_dim, block_dim>>>(
        input,
        output,
        grid_dimensions,
        words_per_row,
        row_shift,
        total_words
    );
}

#include <cstdint>
#include <cstddef>
#include <cuda_runtime.h>

// Bring commonly used fixed-width types into the global namespace for brevity.
using std::uint64_t;
using std::size_t;

/*
 * 3-input carry-save adder (full adder) operating on 64 lanes in parallel.
 *
 * For each bit position i:
 *   a_i + b_i + c_i = (sum_i) + 2 * (carry_i)
 *
 * sum   = a XOR b XOR c
 * carry = majority(a, b, c) = (a & b) | (a & c) | (b & c)
 *
 * This is the fundamental primitive used to accumulate neighbor counts
 * for Conway's Game of Life in a bit-parallel fashion.
 */
static __device__ __forceinline__ void csa3(uint64_t a, uint64_t b, uint64_t c,
                                            uint64_t &sum, uint64_t &carry)
{
    sum   = a ^ b ^ c;
    carry = (a & b) | (a & c) | (b & c);
}

/*
 * CUDA kernel: compute one Game of Life step on a bit-packed grid.
 *
 * - The grid is square of dimension grid_dim x grid_dim cells.
 * - Each 64-bit word encodes 64 consecutive cells in a row (bit 0 = column 0).
 * - words_per_row = grid_dim / 64.
 * - One CUDA thread processes exactly one 64-bit word (i.e., 64 cells).
 *
 * Neighbor counting:
 *   For each word we load the 3x3 block of neighboring words (up to 9 words):
 *
 *        nL   nC   nR        row-1 (north)
 *        cL   C    cR        row
 *        sL   sC   sR        row+1 (south)
 *
 *   For each of the three rows we construct three shifted words:
 *     - Row above:  upL (NW), upC (N),  upR (NE)
 *     - Row center: midL (W),  0,       midR (E)  (center cell excluded)
 *     - Row below:  dnL (SW), dnC (S),  dnR (SE)
 *
 *   These eight directions form the 8 neighbors for every bit in the center word.
 *
 *   We then:
 *     1. Use csa3 (full adder) per row to add its three direction words:
 *          top_count  = upL + upC + upR
 *          mid_count  = midL + 0   + midR
 *          bot_count  = dnL + dnC + dnR
 *        Each count in [0,3] is represented as two bitplanes (sum, carry):
 *          row_sum, row_carry  with: row_count = row_sum + 2 * row_carry
 *
 *     2. Add the three row sums (top_sum, mid_sum, bot_sum) with csa3 to
 *        obtain:
 *          S_sum, S_carry
 *        representing:
 *          S_part = top_sum + mid_sum + bot_sum
 *
 *     3. Similarly add the three row carries (top_carry, mid_carry, bot_carry)
 *        with csa3 to get:
 *          C_sum, C_carry
 *        representing:
 *          C_part = top_carry + mid_carry + bot_carry
 *
 *        Note: each row_carry already has weight 2, so C_part contributes
 *              2 * C_part to the neighbor count.
 *
 *     4. Combining everything, for each bit position:
 *
 *          neighbor_count =
 *              S_sum                      (1's place)
 *            + 2 * (S_carry + C_sum)      (2's place)
 *            + 4 * C_carry                (4's and 8's place)
 *
 *        We compute the bit-sliced representation (n0, n1, n2, n3) such that:
 *
 *          neighbor_count = n0 + 2*n1 + 4*n2 + 8*n3
 *
 *        Derivation:
 *          Let T = S_carry + C_sum, T in {0,1,2}:
 *            t0 = S_carry XOR C_sum  (T % 2)
 *            t1 = S_carry &   C_sum  (T == 2)
 *
 *          Let Q = t1 + C_carry, Q in {0,1,2}:
 *            q0 = t1 XOR C_carry     (Q % 2)
 *            q1 = t1 &   C_carry     (Q == 2)
 *
 *          Then:
 *            neighbor_count = S_sum + 2*t0 + 4*q0 + 8*q1
 *
 *          So:
 *            n0 = S_sum
 *            n1 = t0
 *            n2 = q0
 *            n3 = q1
 *
 *     5. Apply Game of Life rules using these bitplanes:
 *          - eq2: neighbor_count == 2  => n3=0, n2=0, n1=1, n0=0
 *          - eq3: neighbor_count == 3  => n3=0, n2=0, n1=1, n0=1
 *
 *          eq2_mask = !n3 & !n2 &  n1 & !n0
 *          eq3_mask = !n3 & !n2 &  n1 &  n0
 *
 *        Next state:
 *          - A dead cell becomes alive if eq3.
 *          - A live cell survives if it has 2 or 3 neighbors.
 *
 *        Bitwise:
 *           next = eq3 | (C & eq2);
 *
 * Boundary handling:
 *   Cells outside the grid are treated as dead (0). For words on the borders
 *   of the grid, the corresponding neighbor words are set to 0 by checking
 *   row/column bounds before loading.
 */
static __global__ void game_of_life_step_kernel(
    const uint64_t* __restrict__ input,
    uint64_t* __restrict__       output,
    int                          grid_dim,
    int                          words_per_row,
    size_t                       total_words)
{
    size_t idx = static_cast<size_t>(blockIdx.x) * blockDim.x +
                 static_cast<size_t>(threadIdx.x);

    if (idx >= total_words) {
        return;
    }

    const size_t wpr = static_cast<size_t>(words_per_row);

    // Derive 2D position (row, col) of this word in the word grid.
    size_t row = idx / wpr;
    size_t col = idx - row * wpr;
    size_t row_base = row * wpr;

    const bool has_top    = (row > 0);
    const bool has_bottom = (row + 1 < static_cast<size_t>(grid_dim));
    const bool has_left   = (col > 0);
    const bool has_right  = (col + 1 < wpr);

    // Center word (current row, current column).
    const uint64_t C = input[idx];

    // Neighbor words (initialize to 0 for out-of-bounds).
    uint64_t nC = 0, nL = 0, nR = 0;  // Row above
    uint64_t sC = 0, sL = 0, sR = 0;  // Row below
    uint64_t cL = 0, cR = 0;          // Same row, left/right

    if (has_top) {
        const size_t north_base = row_base - wpr;
        nC = input[north_base + col];
        if (has_left)  nL = input[north_base + (col - 1)];
        if (has_right) nR = input[north_base + (col + 1)];
    }

    if (has_bottom) {
        const size_t south_base = row_base + wpr;
        sC = input[south_base + col];
        if (has_left)  sL = input[south_base + (col - 1)];
        if (has_right) sR = input[south_base + (col + 1)];
    }

    if (has_left)  cL = input[row_base + (col - 1)];
    if (has_right) cR = input[row_base + (col + 1)];

    // Construct direction words for each row:
    // Row above: NW, N, NE
    const uint64_t upL = (nC << 1) | (nL >> 63);  // NW
    const uint64_t upC = nC;                      // N
    const uint64_t upR = (nC >> 1) | (nR << 63);  // NE

    // Row center: W, 0 (no self), E
    const uint64_t midL = (C << 1) | (cL >> 63);  // W
    const uint64_t midC = 0ull;                   // Center cell not counted
    const uint64_t midR = (C >> 1) | (cR << 63);  // E

    // Row below: SW, S, SE
    const uint64_t dnL = (sC << 1) | (sL >> 63);  // SW
    const uint64_t dnC = sC;                      // S
    const uint64_t dnR = (sC >> 1) | (sR << 63);  // SE

    // Row-wise sums using 3-input adders.
    uint64_t top_s, top_c;
    uint64_t mid_s, mid_c;
    uint64_t bot_s, bot_c;

    csa3(upL,  upC,  upR,  top_s, top_c);  // top row: NW + N + NE
    csa3(midL, midC, midR, mid_s, mid_c);  // middle row: W + 0 + E
    csa3(dnL,  dnC,  dnR,  bot_s, bot_c);  // bottom row: SW + S + SE

    // Combine the three row sums (sum bitplanes).
    uint64_t S_sum, S_carry;
    csa3(top_s, mid_s, bot_s, S_sum, S_carry);

    // Combine the three row carries (carry bitplanes).
    uint64_t C_sum, C_carry;
    csa3(top_c, mid_c, bot_c, C_sum, C_carry);

    // Compute intermediate totals:
    // T = S_carry + C_sum,  where:
    //   t0 = T % 2,  t1 = (T == 2)
    const uint64_t t0 = S_carry ^ C_sum;
    const uint64_t t1 = S_carry & C_sum;

    // Q = t1 + C_carry, where:
    //   q0 = Q % 2 (4's bit of neighbor_count)
    //   q1 = (Q == 2) (8's bit of neighbor_count)
    const uint64_t q0 = t1 ^ C_carry;
    const uint64_t q1 = t1 & C_carry;

    // Neighbor count bitplanes:
    const uint64_t n0 = S_sum;  // 1's bit
    const uint64_t n1 = t0;     // 2's bit
    const uint64_t n2 = q0;     // 4's bit
    const uint64_t n3 = q1;     // 8's bit (only non-zero when count == 8)

    // Masks for neighbors == 2 and neighbors == 3.
    const uint64_t not_n0 = ~n0;
    const uint64_t not_n2 = ~n2;
    const uint64_t not_n3 = ~n3;

    const uint64_t eq2 = not_n3 & not_n2 &  n1 & not_n0;  // count == 2
    const uint64_t eq3 = not_n3 & not_n2 &  n1 &  n0;     // count == 3

    // Game of Life transition:
    //   next_alive = (neighbor_count == 3) OR (alive & neighbor_count == 2)
    const uint64_t next = eq3 | (C & eq2);

    output[idx] = next;
}

/*
 * Host function: run one step of Conway's Game of Life on a bit-packed grid.
 *
 * Parameters:
 *   - input:  device pointer to current grid (bit-packed, 64 cells per uint64_t).
 *   - output: device pointer to destination grid for next state.
 *   - grid_dimensions: width and height of square grid in cells (power of 2).
 *
 * The input and output arrays must already be allocated with cudaMalloc.
 * This function launches the CUDA kernel but does not perform any
 * host-device synchronization; the caller is responsible for that.
 */
void run_game_of_life(const std::uint64_t* input,
                      std::uint64_t*       output,
                      int                  grid_dimensions)
{
    const int    words_per_row = grid_dimensions >> 6;  // grid_dimensions / 64
    const size_t total_words   =
        static_cast<size_t>(grid_dimensions) *
        static_cast<size_t>(words_per_row);

    // Choose a reasonable block size for modern data center GPUs.
    const int block_dim = 256;
    const int grid_dim =
        static_cast<int>((total_words + block_dim - 1) / block_dim);

    // Launch kernel: one thread per 64-bit word.
    game_of_life_step_kernel<<<grid_dim, block_dim>>>(
        reinterpret_cast<const uint64_t*>(input),
        reinterpret_cast<uint64_t*>(output),
        grid_dimensions,
        words_per_row,
        total_words);
}

